#include <bits/stdc++.h>
using namespace std;
int n , k;
int a[10005];
int dp[10005];
int main() {
	cin >> n >> k;
	for( int i = 1 ; i <= n ; i++ ) {
		cin >> a[i];
		int tmp = a[i];
		for( int j = i - 1 ; j >= max( 0 , i - k ) ; j-- ) {
			tmp = max( tmp , a[j + 1] );
			dp[i] = max( dp[i] , dp[j] + ( i - j ) * tmp );
		}
	}
	cout << dp[n];
	return 0;
}
